define({"topics":[{"title":"Global GDS oversampling","shortdesc":"<p class=\"shortdesc\">Description of the global GDS oversampling feature, which greatly increases the     frequency at which GDSs are sampled to avoid sampling errors. In cases where more than one GDS     transition can happen during one simulation step, see Switch-level GDS oversampling instead. <\/p>","href":"t-ug002\/concepts\/global_gds_oversampling.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e1954","topics":[]},{"title":"Switch-level GDS oversampling","shortdesc":"<p class=\"shortdesc\">Overview and description of the Switch-level GDS oversampling feature in Typhoon HIL     Control Center. Switch-level GDS oversampling is designed to compensate all GDS transitions within one     simulation step, in contrast to global GDS oversampling.<\/p>","href":"t-ug002\/concepts\/switch_level_gds_oversampling.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e1965","topics":[]}]});